module top_module(CLK,Rst,Sm,M);input CLK,Rst,Sm;
	reg [2:0]count;
	output wire M;


	  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @ (posedge CLK or posedge dbg_halt)
			if (Rst|M) 
				count=3'd0;
			else if (Sm)
				count=count+1'b1;
		   else 
				count=count;

		assign M=(count==3'b001);


endmodule
